-- ============================================================================
-- v3 PROD CLEANUP — one-shot fix for drift identified on 2026-04-21
-- ============================================================================
-- Runs in a single transaction. Review output counts after each step.
-- Safe to re-run: all UPDATEs are idempotent (re-running finds 0 rows).
--
-- Scope:
--   1) Record date mismatches      — 176 records, pinned to parent tx date
--   2) Record reverse drift        — 220 records (v3 active, v2 deleted)
--   3) Transaction reverse drift   —  35 txs (v3 active, v2 deleted)
-- ============================================================================

BEGIN;

-- ---------------------------------------------------------------------------
-- STEP 1: Pin record transaction_date to parent tx transaction_date
-- ---------------------------------------------------------------------------
UPDATE transaction_records tr
SET transaction_date = t.transaction_date,
    updated_date = NOW()
FROM transactions t
WHERE tr.id = ANY(t.transaction_records)
  AND t.migration_id IS NOT NULL
  AND tr.migration_id IS NOT NULL
  AND DATE_TRUNC('day', t.transaction_date) <> DATE_TRUNC('day', tr.transaction_date);
-- Expected ~176 rows

-- ---------------------------------------------------------------------------
-- STEP 2: Record reverse drift — soft-delete + fix parent totals
--   v2 record is soft-deleted but v3 copy is still active and counting.
-- ---------------------------------------------------------------------------
-- 2a. Capture affected parent tx IDs before deleting
CREATE TEMP TABLE affected_txs_step2 AS
SELECT DISTINCT t.id AS tx_id
FROM transaction_records tr
JOIN transactions t ON tr.id = ANY(t.transaction_records)
WHERE tr.migration_id IN (102129,102130,102131,102132,102133,102134,102135,102136,102137,102138,102139,102140,102141,102142,102143,102147,102148,102149,102150,102151,102162,102163,102164,102165,102166,102167,102168,102169,102170,102171,102172,102173,102174,102175,102305,102306,102307,102308,102309,102310,102311,102312,102313,110120,110121,110122,110123,110124,110125,110126,110127,110128,110129,110130,110131,110132,110133,110134,110135,110136,110137,110138,110139,113329,113330,113331,113332,113333,113334,113335,113336,113337,115468,115469,115470,115471,115472,115473,115474,115475,115476,115478,115479,115480,115481,115482,119828,119829,119830,119831,119832,119833,129533,129534,129535,129536,129537,129538,129539,129540,129541,129542,129543,130643,130644,130645,130646,130647,130648,130649,130650,130651,136983,136984,136985,136986,136987,136988,137969,137970,137971,137972,137973,137974,137975,137976,137977,137982,137983,137984,137985,137986,137987,137988,137989,137990,137991,138300,138301,138302,138303,138304,138305,138306,138307,138308,138309,139650,141989,141990,141991,141992,141993,141994,141995,141996,141997,149258,149259,149260,149261,149262,149263,149264,149265,149266,149934,149935,149972,149973,149975,149991,150111,150112,150231,150232,150233,150234,150235,150236,150237,150238,150255,150256,150261,150262,150301,150474,150475,150479,150480,150481,150483,150668,150677,150735,150768,150769,150834,150835,150836,150837,150848,150896,150897,151013,151014,151015,151016,151017,151109,151110,151178,151193,151339,151491,151492,151495,85454,85455)
  AND tr.is_active = true AND tr.deleted_date IS NULL;

-- 2b. Soft-delete the ghost records
UPDATE transaction_records
SET deleted_date = NOW(), is_active = false, updated_date = NOW()
WHERE migration_id IN (102129,102130,102131,102132,102133,102134,102135,102136,102137,102138,102139,102140,102141,102142,102143,102147,102148,102149,102150,102151,102162,102163,102164,102165,102166,102167,102168,102169,102170,102171,102172,102173,102174,102175,102305,102306,102307,102308,102309,102310,102311,102312,102313,110120,110121,110122,110123,110124,110125,110126,110127,110128,110129,110130,110131,110132,110133,110134,110135,110136,110137,110138,110139,113329,113330,113331,113332,113333,113334,113335,113336,113337,115468,115469,115470,115471,115472,115473,115474,115475,115476,115478,115479,115480,115481,115482,119828,119829,119830,119831,119832,119833,129533,129534,129535,129536,129537,129538,129539,129540,129541,129542,129543,130643,130644,130645,130646,130647,130648,130649,130650,130651,136983,136984,136985,136986,136987,136988,137969,137970,137971,137972,137973,137974,137975,137976,137977,137982,137983,137984,137985,137986,137987,137988,137989,137990,137991,138300,138301,138302,138303,138304,138305,138306,138307,138308,138309,139650,141989,141990,141991,141992,141993,141994,141995,141996,141997,149258,149259,149260,149261,149262,149263,149264,149265,149266,149934,149935,149972,149973,149975,149991,150111,150112,150231,150232,150233,150234,150235,150236,150237,150238,150255,150256,150261,150262,150301,150474,150475,150479,150480,150481,150483,150668,150677,150735,150768,150769,150834,150835,150836,150837,150848,150896,150897,151013,151014,151015,151016,151017,151109,151110,151178,151193,151339,151491,151492,151495,85454,85455)
  AND is_active = true AND deleted_date IS NULL;
-- Expected ~220 rows

-- 2c. Prune transaction_records[] and recompute parent totals
UPDATE transactions t SET
  transaction_records = (
    SELECT COALESCE(array_agg(rid ORDER BY rid), ARRAY[]::bigint[])
    FROM unnest(t.transaction_records) AS rid
    WHERE NOT EXISTS (
      SELECT 1 FROM transaction_records tr
      WHERE tr.id = rid AND tr.deleted_date IS NOT NULL
    )
  ),
  weight_kg = COALESCE((
    SELECT SUM(tr.origin_weight_kg) FROM transaction_records tr
    WHERE tr.id = ANY(t.transaction_records)
      AND tr.is_active = true AND tr.deleted_date IS NULL
  ), 0),
  total_amount = COALESCE((
    SELECT SUM(tr.total_amount) FROM transaction_records tr
    WHERE tr.id = ANY(t.transaction_records)
      AND tr.is_active = true AND tr.deleted_date IS NULL
  ), 0),
  updated_date = NOW()
WHERE t.id IN (SELECT tx_id FROM affected_txs_step2);
-- Expected ~58 rows

-- ---------------------------------------------------------------------------
-- STEP 3: Transaction reverse drift — soft-delete + cascade records
--   v2 tx is soft-deleted but v3 copy is still active.
-- ---------------------------------------------------------------------------
-- 3a. Cascade soft-delete records of the ghost txs FIRST
UPDATE transaction_records SET
  deleted_date = NOW(), is_active = false, updated_date = NOW()
WHERE deleted_date IS NULL AND id IN (
  SELECT unnest(t.transaction_records) FROM transactions t
  WHERE t.migration_id IN (143701,143703,143714,143810,143862,143863,143867,143886,
    144002,144006,144007,144009,144157,144164,144207,144231,144232,144289,
    144290,144291,144298,144329,144416,144417,144418,144419,144482,144540,
    144549,144792,144980,144981,144984,25881,63195)
    AND t.is_active = true AND t.deleted_date IS NULL
);

-- 3b. Soft-delete the tx itself
UPDATE transactions SET
  deleted_date = NOW(), is_active = false, updated_date = NOW()
WHERE migration_id IN (143701,143703,143714,143810,143862,143863,143867,143886,
    144002,144006,144007,144009,144157,144164,144207,144231,144232,144289,
    144290,144291,144298,144329,144416,144417,144418,144419,144482,144540,
    144549,144792,144980,144981,144984,25881,63195)
  AND is_active = true AND deleted_date IS NULL;
-- Expected ~35 rows

-- ---------------------------------------------------------------------------
-- VERIFY: all three drift types should now be 0
-- ---------------------------------------------------------------------------
SELECT 'remaining_date_mismatches' AS check_name, COUNT(*) AS remaining
FROM transactions t
JOIN transaction_records tr ON tr.id = ANY(t.transaction_records)
WHERE t.migration_id IS NOT NULL AND tr.migration_id IS NOT NULL
  AND DATE_TRUNC('day', t.transaction_date) <> DATE_TRUNC('day', tr.transaction_date)
UNION ALL
SELECT 'remaining_ghost_records' AS check_name, COUNT(*) AS remaining
FROM transaction_records
WHERE migration_id IN (102129,102130,102131,102132,102133,102134,102135,102136,102137,102138,102139,102140,102141,102142,102143,102147,102148,102149,102150,102151,102162,102163,102164,102165,102166,102167,102168,102169,102170,102171,102172,102173,102174,102175,102305,102306,102307,102308,102309,102310,102311,102312,102313,110120,110121,110122,110123,110124,110125,110126,110127,110128,110129,110130,110131,110132,110133,110134,110135,110136,110137,110138,110139,113329,113330,113331,113332,113333,113334,113335,113336,113337,115468,115469,115470,115471,115472,115473,115474,115475,115476,115478,115479,115480,115481,115482,119828,119829,119830,119831,119832,119833,129533,129534,129535,129536,129537,129538,129539,129540,129541,129542,129543,130643,130644,130645,130646,130647,130648,130649,130650,130651,136983,136984,136985,136986,136987,136988,137969,137970,137971,137972,137973,137974,137975,137976,137977,137982,137983,137984,137985,137986,137987,137988,137989,137990,137991,138300,138301,138302,138303,138304,138305,138306,138307,138308,138309,139650,141989,141990,141991,141992,141993,141994,141995,141996,141997,149258,149259,149260,149261,149262,149263,149264,149265,149266,149934,149935,149972,149973,149975,149991,150111,150112,150231,150232,150233,150234,150235,150236,150237,150238,150255,150256,150261,150262,150301,150474,150475,150479,150480,150481,150483,150668,150677,150735,150768,150769,150834,150835,150836,150837,150848,150896,150897,151013,151014,151015,151016,151017,151109,151110,151178,151193,151339,151491,151492,151495,85454,85455)
  AND is_active = true AND deleted_date IS NULL
UNION ALL
SELECT 'remaining_ghost_txs' AS check_name, COUNT(*) AS remaining
FROM transactions
WHERE migration_id IN (143701,143703,143714,143810,143862,143863,143867,143886,
    144002,144006,144007,144009,144157,144164,144207,144231,144232,144289,
    144290,144291,144298,144329,144416,144417,144418,144419,144482,144540,
    144549,144792,144980,144981,144984,25881,63195)
  AND is_active = true AND deleted_date IS NULL;

DROP TABLE affected_txs_step2;
COMMIT;
